import{_ as a,o as i,c as t,ai as r}from"./chunks/framework.CKB5fCPB.js";const y=JSON.parse('{"title":"Privacy Policy","description":"","frontmatter":{},"headers":[],"relativePath":"Data privacy.md","filePath":"Data privacy.md"}'),s={name:"Data privacy.md"};function n(o,e,l,d,c,p){return i(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="privacy-policy" tabindex="-1">Privacy Policy <a class="header-anchor" href="#privacy-policy" aria-label="Permalink to “Privacy Policy”">​</a></h1><p>DCTS is a self-hosted communication platform designed for decentralized messaging and real-time communication. The developers of DCTS do not operate any central servers and do not collect user data.</p><hr><h2 id="data-processing" tabindex="-1">Data Processing <a class="header-anchor" href="#data-processing" aria-label="Permalink to “Data Processing”">​</a></h2><p>A DCTS &quot;instance&quot; is a server operated by an individual. By default, all data remains on that instance and is not shared with third parties.</p><p>The following data may be processed by a server:</p><ul><li>Account data (ID, public key, profile data such as icon, banner, status, about me)</li><li>Messages (server chats and direct messages)</li><li>Metadata (timestamps, room IDs)</li><li>Connection information (IP address)</li><li>Uploaded content (e.g. images, audio, files)</li><li>Proof-of-Work data (used for abuse prevention)</li></ul><p>For abuse prevention, IP addresses may be checked using a third-party service:</p><ul><li><a href="https://ipapi.is/" target="_blank" rel="noreferrer">https://ipapi.is/</a></li></ul><p>This is used to detect VPNs, proxies, or malicious activity.</p><hr><h2 id="end-to-end-encryption" tabindex="-1">End-to-End Encryption <a class="header-anchor" href="#end-to-end-encryption" aria-label="Permalink to “End-to-End Encryption”">​</a></h2><p>Direct messages can be end-to-end encrypted when using supported clients.</p><ul><li>Only intended recipients can decrypt message content</li><li>Servers and operators cannot read encrypted message content</li><li>Some metadata (e.g. sender, timestamps) remains visible for functionality</li></ul><hr><h2 id="responsibility" tabindex="-1">Responsibility <a class="header-anchor" href="#responsibility" aria-label="Permalink to “Responsibility”">​</a></h2><p>DCTS is fully self-hosted. Each server operator is responsible for:</p><ul><li>Data storage</li><li>Logging</li><li>Moderation</li><li>Legal compliance</li></ul><p>DCTS developers do not have access to data stored on third-party servers.</p><hr><h2 id="data-storage" tabindex="-1">Data Storage <a class="header-anchor" href="#data-storage" aria-label="Permalink to “Data Storage”">​</a></h2><p>All data is stored on the server you connect to. There is no central database or CDN operated by DCTS.</p><p>Official clients may store data locally on the device, including:</p><ul><li>Account data</li><li>Public and private keys</li></ul><p>Private keys are stored locally and are never transmitted to servers.</p><hr><h2 id="data-sharing" tabindex="-1">Data Sharing <a class="header-anchor" href="#data-sharing" aria-label="Permalink to “Data Sharing”">​</a></h2><p>DCTS does not sell or share personal data.</p><p>Data is only transmitted between servers when required for core functionality (e.g. message delivery).</p><hr><h2 id="changes" tabindex="-1">Changes <a class="header-anchor" href="#changes" aria-label="Permalink to “Changes”">​</a></h2><p>This privacy policy may be updated. Continued use of DCTS implies acceptance of any changes.</p>',32)])])}const m=a(s,[["render",n]]);export{y as __pageData,m as default};
